func (s *ServerPool) MarkBackendStatus(backendURL *url.URL, alive bool) {
    for _, b := range s.backends {
        if b.URL.String() == backendURL.String() {
            b.Alive = alive
            return
        }
    }
}

func main() {
    pool := &ServerPool{}
    urls := []string{"http://localhost:8081", "http://localhost:8082", "http://localhost:8083"}
    for _, u := range urls {
        b, _ := NewBackend(u)
        pool.AddBackend(b)
    }

    downURL, _ := url.Parse("http://localhost:8082")
    pool.MarkBackendStatus(downURL, false)

    for i := 0; i < 6; i++ {
        peer := pool.GetNextPeer()
        if peer != nil {
            fmt.Println(peer.URL.Host)
        }
    }
    // Expected: only 8081 and 8083 appear
}
```

statement:
Explain why the following `NextIndex` implementation has a data race, and rewrite it to be race-free using `sync/atomic`:

```go
func (s *ServerPool) NextIndex() int {
    s.current++
    return int(s.current % uint64(len(s.backends)))
}
```

solution:
`s.current++` is not atomic. It compiles to three operations: load `s.current`, add 1, store the result. Two goroutines can interleave these steps, causing one increment to be lost. Go's race detector will flag this.

`atomic.AddUint64` performs the read-modify-write as a single uninterruptible CPU instruction, so no goroutine can observe an intermediate state.

Race-free version:

```go
func (s *ServerPool) NextIndex() int {
    return int(atomic.AddUint64(&s.current, 1) % uint64(len(s.backends)))
}
```
